VALUES
  ('judicial-57f41407-moex-00563', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '假設臺、日兩國間是根據比較利益法則分工，若臺灣專門負責生產烏魚子，而日本專門生產櫻花蝦， 且兩國進行自由貿易。在不考慮其他條件情況，下列對於兩國間國際貿易的敘述，何者正確？', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00564', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '若某國之政府財政結構已達舉債上限、內需市場不振、國內外投資者裹足不前，但GDP的表現卻呈 現正成長的態勢。若從GDP的支出面分析，試問對GDP貢獻最多的應指下列何者？ consumption expenditure）  investment） government expenditure）  net exports）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00565', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '經許多醫學研究證實，吸菸者將引發中風、癌症等疾病，吸入二手菸可能引發的疾病與吸菸者無異， 相關研究指出在有人抽菸的工作場所八小時，相當於吸了六根菸，因而我國制定菸害防制法以規範相 關場所禁止吸菸，並且在菸品價格中徵收健康福利捐。下列針對上文的分析敘述，何者正確？', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00566', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', 'Ａ國近年來因需求不振導致景氣衰退，因此在經濟指標上，該國最有可能發生下列何種現象？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00567', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '綠島某民宿業者捕殺保育魚類龍王鯛，引發民眾強力譴責，海洋委員會海巡署將民宿業者移送法辦。 依財貨的性質來分類，保育魚類龍王鯛屬於下列何者？', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00568', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '阿軒去年五月購買一萬美元並定存一年，存款利率為3%。若今年的匯率與利率和去年五月相同，美 元兌換新臺幣之即期買進匯率為32元，賣出即期匯率為30元。在不考慮其他條件的情況下，下列關 於阿軒投資美元定存收益的敘述，何者正確？ 30萬元 300元 1萬1000元 32萬9600元', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00569', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '某國計算 CPI 時，只計算麵包、手機、衛生紙 3 種品項，下表為該國近三年三種產品價格與消費數 量。若以T年作為基期，T+2年的CPI應為下列何者？ 年度  T  T+1  T+2 價格  數量  價格  數量  價格  數量 麵包  60  10  80  8  120  5 手機  330  10  300  11  330  11 衛生紙  10  10  15  10  25  5', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00570', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '110  119  120', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 109, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00571', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '製糖的原料除了甘蔗之外，另一種是甜菜。甘蔗是熱帶植物，只能生長在溫暖的南方，而甜菜卻是種 在雨水少的寒冷北方。假若歐洲今年因氣候變異，導致甜菜生產銳減，甜菜價格上漲，在其他條件不 變的情況下，則全球甘蔗市場將因此產生下列何種變化？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00572', 'judicial-57f41407', 'judicial-57f41407-moex-111-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '政黨與利益團體都在民主政治中扮演重要角色，下列有關兩者的敘述何者正確？ 理念相同的人所組成的', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "c4fa0adbd37d", "answer_pdf_sha1": "1781c15a5551", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
